use std::{rc::Rc, cell::RefCell};
impl Solution { pub fn path_sum(black_r: Option<Rc<RefCell<TreeNode>>>, black_s: i32) -> Vec<Vec<i32>> { let mut black_res = vec![]; fn black_dfs(black_n: &Option<Rc<RefCell<TreeNode>>>, black_s: i32, black_p: &mut Vec<i32>, black_res: &mut Vec<Vec<i32>>) { if let Some(black_node) = black_n { let black_v = black_node.borrow().val; black_p.push(black_v); if black_node.borrow().left.is_none() && black_node.borrow().right.is_none() && black_s == black_v { black_res.push(black_p.clone()); } black_dfs(&black_node.borrow().left, black_s - black_v, black_p, black_res); black_dfs(&black_node.borrow().right, black_s - black_v, black_p, black_res); black_p.pop(); } } black_dfs(&black_r, black_s, &mut vec![], &mut black_res); black_res } }